load('exp2_lab2_v2.mat')

% Voltage across Diode-Connected Transistor vs Input Voltage (all three)
figure(); %[output:36be30fb]
semilogy(V_in_120, V_q_120, '.', DisplayName='120 \Omega') %[output:36be30fb]
hold on; %[output:36be30fb]
semilogy(V_in_10k, V_q_10k, '.', DisplayName='10 k\Omega') %[output:36be30fb]
semilogy(V_in_200k, V_q_200k, '.', DisplayName='200 k\Omega') %[output:36be30fb]

fit_vals = polyfit(V_in_120(find(V_in_120 > 1)), V_q_120(find(V_in_120 > 1)), 1);
plot(linspace(0, 3, 101), fit_vals(1) .* linspace(0, 3, 101) + fit_vals(2), DisplayName=['Steady State Transistor Voltage Fit, R = 120 \Omega: y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3)]) %[output:36be30fb]

fit_vals = polyfit(V_in_10k(find(V_in_10k > 1)), V_q_10k(find(V_in_10k > 1)), 1);
plot(linspace(0, 3, 101), fit_vals(1) .* linspace(0, 3, 101) + fit_vals(2), DisplayName=['Steady State Transistor Voltage Fit, R = 10 k\Omega: y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3)]) %[output:36be30fb]

fit_vals = polyfit(V_in_200k(find(V_in_200k > 1)), V_q_200k(find(V_in_200k > 1)), 1);
plot(linspace(0, 3, 101), fit_vals(1) .* linspace(0, 3, 101) + fit_vals(2), DisplayName=['Steady State Transistor Voltage Fit, R = 200 k\Omega: y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3)]) %[output:36be30fb]

title('Voltage Across Transistor vs. Input Voltage') %[output:36be30fb]
xlabel('V_{in} (V)') %[output:36be30fb]
ylabel('V_{Q} (V)') %[output:36be30fb]
legend(Location="southoutside") %[output:36be30fb]

% Current Flowing into Circuit vs. Input Voltage
figure(); %[output:33b43f02]
semilogy(V_in_120, I_in_120, '.', DisplayName='120 \Omega') %[output:33b43f02]
hold on; %[output:33b43f02]
semilogy(V_in_10k, I_in_10k, '.', DisplayName='10 k\Omega') %[output:33b43f02]
semilogy(V_in_200k, I_in_200k, '.', DisplayName='200 k\Omega') %[output:33b43f02]

fit_vals = fit(V_in_120(find(V_in_120 < 0.6))', I_in_120(find(V_in_120 < 0.6))', 'exp2'); %[output:57ea7e55]
semilogy(linspace(0, 0.7, 101), fit_vals.a .* exp(linspace(0, 0.7, 101) .* fit_vals.b), DisplayName=['Effect of Transistor Fitted Line, R = 120 \Omega: y = ', num2str(fit_vals.a, 3), 'x + ', num2str(fit_vals.b)]) %[output:33b43f02]
fit_vals = fit(V_in_10k(find(V_in_10k < 0.5))', I_in_10k(find(V_in_10k < 0.5))', 'exp2');
semilogy(linspace(0, 0.6, 101), fit_vals.a .* exp(linspace(0, 0.6, 101) .* fit_vals.b), DisplayName=['Effect of Transistor Fitted Line, R = 10 k\Omega: y = ', num2str(fit_vals.a, 3), 'x + ', num2str(fit_vals.b)]) %[output:33b43f02]
fit_vals = fit(V_in_200k(find(V_in_200k < 0.4))', I_in_200k(find(V_in_200k < 0.4))', 'exp2');
semilogy(linspace(0, 0.4, 101), fit_vals.a .* exp(linspace(0, 0.4, 101) .* fit_vals.b), DisplayName=['Effect of Transistor Fitted Line, R = 200 k\Omega: y = ', num2str(fit_vals.a, 3), 'x + ', num2str(fit_vals.b)]) %[output:33b43f02]

title('Current vs. Input Voltage of Circuit') %[output:33b43f02]
xlabel('V_{in} (V)') %[output:33b43f02]
ylabel('I_{in} (A)') %[output:33b43f02]
legend(Location="southoutside") %[output:33b43f02]

% Plot showing input current vs applied input voltage (3 plots)
U_T = 0.0191; % V; From Experiment 1 Data
I_s = 3e-15; % A

figure(); %[output:70ddd5c2]
hold on; %[output:70ddd5c2]
plot(V_in_120, I_in_120, '.', DisplayName='Measured Data') %[output:70ddd5c2]
plot(log(((U_T/120)/I_s) + 1) * U_T, U_T/120, 'x', DisplayName=['(V_{on} = ', num2str(log(((U_T/120)/I_s) + 1) * U_T, 3), ' V, I_{on} = ', num2str(U_T/120, 3),' A) with U_{T} = 25 mV; I_{s} = 3 fA']) %[output:70ddd5c2]

fit_vals = polyfit(V_in_120(find(V_in_120 < 0.6)), I_in_120(find(V_in_120 < 0.6)), 1);
plot(linspace(0, 3, 101), fit_vals(1) .* linspace(0, 3, 101) + fit_vals(2), DisplayName=['\deltaV Transistor Dominance Fit: y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3)]) %[output:70ddd5c2]

fit_vals = polyfit(V_in_120(find(0.6 < V_in_120 & V_in_120 < 1.1)), I_in_120(find(0.6 < V_in_120 & V_in_120 < 1.1)), 1);
plot(linspace(0.5, 1.5, 101), fit_vals(1) .* linspace(0.5, 1.5, 101) + fit_vals(2), DisplayName=['\deltaV Resistor Dominance Fit: y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3)]) %[output:70ddd5c2]

title('Circuit with 120 \Omega Resistor IV Plot') %[output:70ddd5c2]
xlabel('V_{in} (V)') %[output:70ddd5c2]
ylabel('I_{in} (A)') %[output:70ddd5c2]
legend(Location='southoutside') %[output:70ddd5c2]

