% figure();
% hold on;
% plot(log(((U_T/120)/I_s) + 1) * U_T, U_T/120, 'x', DisplayName='(V_{on}, I_{on}) with U_{T} = 25 mV; I_{s} = 3 fA; R = 120 \Omega')
% plot(log(((U_T/10e3)/I_s) + 1) * U_T, U_T/10e3, 'x', DisplayName='(V_{on}, I_{on}) with U_{T} = 25 mV; I_{s} = 3 fA; R = 10 k\Omega')
% plot(log(((U_T/200e3)/I_s) + 1) * U_T, U_T/200e3, 'x', DisplayName='(V_{on}, I_{on}) with U_{T} = 25 mV; I_{s} = 3 fA; R = 200 k\Omega')
% xlabel('V_{on} (V)')
% ylabel('I_{on} (A)')
% legend(Location='best')

% V_on and I_on as a function of R w/ Data
R_vals = linspace(0, 1e6, 1e6);

RGB = orderedcolors("gem");
default_colors = rgb2hex(RGB);

figure(); %[output:89e0ef1d]
yyaxis left %[output:89e0ef1d]
loglog(R_vals, U_T ./ R_vals) %[output:89e0ef1d]
hold on; %[output:89e0ef1d]
xlabel('Resistance in Series (R)') %[output:89e0ef1d]
ylabel('I_{on} (A)') %[output:89e0ef1d]
yyaxis right %[output:89e0ef1d]
ylabel('V_{on} (V)') %[output:89e0ef1d]
semilogx(R_vals, log(((U_T./R_vals)/I_s) + 1) .* U_T) %[output:89e0ef1d]

yyaxis left %[output:89e0ef1d]
semilogx(120, U_T/120, 'x', Color=default_colors(5), LineWidth=2) %[output:89e0ef1d]
semilogx(10e3, U_T/10e3, 'x', Color=default_colors(6),LineWidth=2) %[output:89e0ef1d]
semilogx(200e3, U_T/200e3, 'x', Color=default_colors(7), LineWidth=2) %[output:89e0ef1d]
yyaxis right %[output:89e0ef1d]
semilogx(120, log(((U_T/120)/I_s) + 1) * U_T, 'x', Color=default_colors(5), LineWidth=2) %[output:89e0ef1d]
semilogx(10e3, log(((U_T/10e3)/I_s) + 1) * U_T, 'x', Color=default_colors(6), LineWidth=2) %[output:89e0ef1d]
semilogx(200e3, log(((U_T/200e3)/I_s) + 1) * U_T, 'x', Color=default_colors(7), LineWidth=2) %[output:89e0ef1d]

title('V_{on} and I_{on} with respect to R') %[output:89e0ef1d]
legend('I_{on} = U_{T}/R Theoretical Fit', 'R = 120 \Omega', 'R = 10 k\Omega', 'R = 200 k\Omega', 'V_{on} = ln(U_{T}/R)/I_{s} + 1 Theoretical Fit', '', '', '',Location='southoutside') %[output:89e0ef1d] %[output:28018a73]

